using System.Collections;
using TMPro;
using UnityEngine;

/// <summary>
/// Ecrã de "SUCESSO!"/"FALHOU" no fim de um Desafio (Sistema de
/// Missões/Desafios, Tarefa #12): overlay full-screen (CanvasGroup, Screen
/// Space - Overlay) com fade in/out, mostrado a partir de
/// <see cref="ChallengeManager.OnChallengeEnded"/>.
///
/// Sem ecrã para <see cref="ChallengeEndReason.Abandonado"/> (o jogador saiu
/// da zona/portal de propósito — ver ChallengeManager.AbandonChallenge).
///
/// Música/SFX: se <see cref="ChallengeDefinition.successMusic"/>/<see cref="ChallengeDefinition.failMusic"/>
/// estiver definida, este ecrã toca-a (substitui o BGM) durante o overlay e
/// restaura a música da área (AudioManager.RefreshActiveZones) no fim — caso
/// contrário, ChallengeManager já restaurou a música da área antes deste
/// evento disparar. <see cref="ChallengeDefinition.successSfx"/>/<see cref="ChallengeDefinition.failSfx"/>
/// tocam sempre como som único (AudioManager.PlaySE), independentemente da música.
///
/// Singleton com auto-fallback (mesmo padrão de DeathScreenUI/MissionCompleteUI
/// — sem UI montada, ainda assim espera "holdDuration" e restaura a música,
/// apenas sem mostrar nada).
///
/// Montagem no Editor:
/// - Canvas (Screen Space - Overlay) com "panelRoot" + "canvasGroup" no mesmo
///   GameObject.
/// - "titleText" (TMP_Text): "SUCESSO!" / "FALHOU" (ou "successTitle"/"failTitle").
/// - "messageText" (TMP_Text, opcional): mensagem de falha
///   (ChallengeFailCondition.failMessage / "Tempo esgotado!") ou
///   "successMessage" no sucesso.
/// </summary>
public class ChallengeResultUI : MonoBehaviour
{
    public static ChallengeResultUI Instance { get; private set; }

    [Header("Painel")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private CanvasGroup canvasGroup;
    [SerializeField] private TMP_Text titleText;
    [SerializeField] private TMP_Text messageText;

    [Header("Textos Padrão")]
    [SerializeField] private string successTitle = "SUCESSO!";
    [SerializeField] private string failTitle = "FALHOU";

    [Tooltip("Mensagem mostrada no sucesso (a de falha vem de ChallengeFailCondition.failMessage / \"Tempo esgotado!\").")]
    [SerializeField] private string successMessage = "";

    [Header("Tempo (apenas desafios com 'hasTimeLimit')")]
    [Tooltip("Formato da linha de tempo no sucesso. \"{0}\" = tempo do desafio (MM:SS).")]
    [SerializeField] private string timeFormat = "Tempo: {0}";

    [Tooltip("Linha adicional mostrada quando o tempo bate o recorde pessoal anterior (ChallengeManager.LastCompletionIsNewRecord).")]
    [SerializeField] private string newRecordMessage = "Novo Recorde!";

    [Header("Transição")]
    [Tooltip("Duração do fade in/out, em segundos.")]
    [SerializeField] private float fadeDuration = 0.3f;

    [Tooltip("Tempo (s) com o ecrã totalmente visível, sem contar o fade.")]
    [SerializeField] private float holdDuration = 2f;

    private bool isAutoFallback;
    private bool isShowing;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        if (canvasGroup != null)
        {
            canvasGroup.alpha = 0f;
            canvasGroup.blocksRaycasts = false;
        }

        if (panelRoot != null) panelRoot.SetActive(false);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(ChallengeResultUI) + " (Fallback)");
        var instance = go.AddComponent<ChallengeResultUI>();
        instance.isAutoFallback = true;
    }

    private void OnEnable()
    {
        ChallengeManager.OnChallengeEnded += HandleEnded;
    }

    private void OnDisable()
    {
        ChallengeManager.OnChallengeEnded -= HandleEnded;
    }

    private void HandleEnded(ChallengeDefinition challenge, ChallengeEndReason reason, string message)
    {
        if (reason == ChallengeEndReason.Abandonado) return;
        if (isShowing) return;

        StartCoroutine(ShowRoutine(challenge, reason, message));
    }

    private IEnumerator ShowRoutine(ChallengeDefinition challenge, ChallengeEndReason reason, string message)
    {
        isShowing = true;

        bool success = reason == ChallengeEndReason.Sucesso;

        string title = success ? successTitle : failTitle;
        string body = success ? successMessage : (!string.IsNullOrEmpty(message) ? message : "");

        if (success && challenge.hasTimeLimit && ChallengeManager.Instance != null)
        {
            var manager = ChallengeManager.Instance;
            string timeLine = string.Format(timeFormat, ChallengeManager.FormatTime(manager.LastCompletionTimeSeconds));

            body = string.IsNullOrEmpty(body) ? timeLine : $"{body}\n{timeLine}";
            if (manager.LastCompletionIsNewRecord) body += "\n" + newRecordMessage;
        }

        var music = success ? challenge.successMusic : challenge.failMusic;
        var sfx = success ? challenge.successSfx : challenge.failSfx;

        if (music != null) AudioManager.Instance?.PlayBGM(music, fadeTime: fadeDuration, loop: false);
        if (sfx != null) AudioManager.Instance?.PlaySE(sfx);

        // Sem UI montada (instância "Fallback") — apenas espera (e restaura a
        // música, se aplicável), sem overlay.
        if (canvasGroup == null)
        {
            yield return WaitUnscaled(holdDuration);

            if (music != null) AudioManager.Instance?.RefreshActiveZones();

            isShowing = false;
            yield break;
        }

        if (titleText != null) titleText.text = title;
        if (messageText != null) messageText.text = body;

        if (panelRoot != null) panelRoot.SetActive(true);
        canvasGroup.blocksRaycasts = true;

        yield return FadeRoutine(0f, 1f);
        yield return WaitUnscaled(holdDuration);
        yield return FadeRoutine(1f, 0f);

        canvasGroup.blocksRaycasts = false;
        if (panelRoot != null) panelRoot.SetActive(false);

        if (music != null) AudioManager.Instance?.RefreshActiveZones();

        isShowing = false;
    }

    private IEnumerator WaitUnscaled(float duration)
    {
        float t = 0f;
        while (t < duration)
        {
            t += Time.unscaledDeltaTime;
            yield return null;
        }
    }

    private IEnumerator FadeRoutine(float from, float to)
    {
        if (canvasGroup == null) yield break;

        canvasGroup.alpha = from;

        if (fadeDuration <= 0f)
        {
            canvasGroup.alpha = to;
            yield break;
        }

        float t = 0f;
        while (t < fadeDuration)
        {
            t += Time.unscaledDeltaTime;
            canvasGroup.alpha = Mathf.Lerp(from, to, t / fadeDuration);
            yield return null;
        }
        canvasGroup.alpha = to;
    }
}
